        <Other v-for="(other, key) in otherInventories" :id="key" :name="other" :key="key" :drag="dragObject"
            @onMouseDown="onMouseDown" @onDoubleClick="onDoubleClick" />
        <Avatar :drag="dragObject" />
        <Tooltip :adress="addressFix" @split="splitX" @drop="drop2" @use="use" :tooltip="tooltip" @close="closeTooltip"
            v-if="tooltip.show" />
        <Split :from="split.from" :to="split.to" :item="split.item" @onSplitClose="split.close()"
            @onSpliteMove="splitMove" />
        <Confirm :msg="confirm.msg" v-if="confirm.show" @confirmAction="confirmAction" />


        <div class="rubbish" @mouseup="check">
            <div class="rubbish__content">
                <svg width="3vh" viewBox="0 0 23 30" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path fill-rule="evenodd" clip-rule="evenodd"
